VALUES
  ('disabled-c5fb3965-moex-00201', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '依司法院大法官解釋意旨及現行行政訴訟法之規定，甲所有坐落A市之土 地，原來的土地使用分區為加油站用地，A 市政府報經內政部核定後，於 民國 110 年 8 月 23 日發布實施「A 市○○○都市計畫通盤檢討（主要計 畫）案」（下稱系爭公告），將系爭加油站用地變更為「交通用地」。下列 何者錯誤？', '["系爭公告屬法規性質，並不是行政處分，甲不得提起行政訴訟", "系爭公告其中具體項目已有直接限制甲之權益或增加其負擔，屬行政處 分之性質", "甲認為系爭公告違法而直接損害其權利，得依都市計畫審查程序之規 定，提起都市計畫審查訴訟，請求宣告該都市計畫無效", "甲不需經訴願程序，即得提起都市計畫審查訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00202', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '下列何者不得提起都市計畫審查訴訟？', '["人民", "地方自治團體", "公法人", "內政部"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00203', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '對於財產權訴訟之第二審判決上訴，依民事訴訟法相關規定及實務見解， 其上訴所得受之利益最少須逾新臺幣多少數額？', '["100萬元", "150萬元", "200萬元", "250萬元"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00204', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '關於民事訴訟之法院管轄，下列何者正確？', '["請求分割共有土地訴訟，得由共有人住所地法院管轄", "因交通事故發生車禍請求賠償，得由被告住所地法院管轄", "對數人提起訴訟，被告住所不同，僅得由最多被告住所之法院管轄", "買賣房屋糾紛，被告遷居美國，於國內現無住所，原告僅得向美國法院 提起訴訟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00205', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '關於民事訴訟程序之適用，下列何者正確？', '["租期1年，房東請求給付承租100坪店面之6個月租金，應適用通常訴 訟程序", "服飾店店員請求店長給付薪資新臺幣60萬元，應適用小額訴訟程序", "在台一線騎重機被後方汽車追撞，致右腿骨折，請求體傷及車損之賠償， 應適用簡易訴訟程序", "請求返還無償出借之插秧機，得聲請法院發支付命令"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00206', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '下列何者不得聲請法院依督促程序發支付命令？', '["本票執票人請求發票人給付票款", "公司員工請求任職之公司給付薪資", "名譽權受侵害之人請求加害人回復其名譽", "身體權受侵害之人請求加害人賠償其醫藥費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00207', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '下列關於使用借貸性質之敘述，何者正確？', '["不要式契約", "不要物契約", "有償契約", "物權契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00208', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '甲對乙有一債權，本應於民國（下同）110 年 5 月 30 日因時效完成而消 滅，然而甲於同年月 20 日確診新冠肺炎，被送入加護病房治療，於同年 6月30日康復出院。下列何者正確？', '["甲對乙之債權，其時效於110年5月20日中斷，應重新起算", "甲對乙之債權，不因甲確診而影響時效，故仍於 110 年 5 月 30 日完成 時效", "甲對乙之債權於110年6月30日因時效完成而消滅", "甲對乙債權之消滅時效，於110年7月30日完成"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00209', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '85歲之甲因遭遇海難失蹤，下列何者正確？', '["甲失蹤滿3年後，法院亦不得因聲請為死亡之宣告", "甲經法院為死亡宣告者，以裁判內所確定死亡之時，視為其為死亡", "甲經法院為死亡宣告後，如尚生存，而其配偶乙再婚，則甲乙間之婚姻 關係歸於消滅", "甲經法院為死亡宣告後，其權利能力歸於消滅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL),
  ('disabled-c5fb3965-moex-00210', 'disabled-c5fb3965', 'disabled-c5fb3965-moex-113-55d283b0', 'sub-disabled-c5fb3965-05', NULL, 'single_choice', '甲有 A 屋，先賣給乙，並交付於乙使用；嗣後，甲將 A 屋出賣並移轉登 記所有權給丙。下列何者正確？', '["乙得請求丙移轉A屋所有權於乙", "乙得請求甲移轉A屋所有權於乙", "乙得因甲給付不能，請求損害賠償", "乙得拒絕交付房屋於丙"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:56+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "503", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "戶政"}'::jsonb, NULL)
